import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent {
  loginForm: FormGroup;
  errorMessage: string = '';

  // 👇 Agregamos la variable que controla el estado de carga del botón
  isLoading: boolean = false; 

  private fb = inject(FormBuilder);
  private authService = inject(AuthService);
  private router = inject(Router);

  constructor() {
    this.loginForm = this.fb.group({
      email: ['', [Validators.required, Validators.email]],
      // Agregamos minLength(6) para que coincida con la validación de tu HTML
      password: ['', [Validators.required, Validators.minLength(6)]] 
    });
  }

  // 👇 Agregamos los "getters" que tu HTML usa para mostrar los errores en rojo
  get emailControl() {
    return this.loginForm.get('email');
  }

  get passwordControl() {
    return this.loginForm.get('password');
  }

  onSubmit() {
    if (this.loginForm.valid) {
      this.isLoading = true; // Cambiamos el botón a "Ingresando..."
      this.errorMessage = '';

      const { email, password } = this.loginForm.value;

      this.authService.login(email, password).subscribe({
        next: () => {
          this.isLoading = false;
          this.router.navigate(['/']); 
        },
        error: (err) => {
          this.isLoading = false;
          this.errorMessage = err.error?.error || 'Error al iniciar sesión';
        }
      });
    } else {
      this.loginForm.markAllAsTouched();
    }
  }
}
